import { 運筆 } from '../bi.js';
// 寶髻：冠上高髻（頂 z≈0.6–2.5）
export function 寶髻(bi) {
    const { M, Qk, C, S, 衣, 細 } = 運筆(bi);
    衣(() => {
        M(-1.55, 2.4);
        C(-1.75, 0.6, 1.75, 0.6, 1.55, 2.4);
        S();
        細(() => { M(-0.55, 2.0); Qk(-0.25, 1.15, 0.5, 1.05); S(); });
    });
}
// 垂髮：每側二縷，**行於耳後**（耳廓之外讓一分——五地皆髮不掩耳），
// 縷有 S 波，長短相參，末有小卷；耳後之段斷筆讓耳（線描無遮之律）
export function 垂髮(bi) {
    const { M, Qk, C, S, 衣, 細 } = 運筆(bi);
    衣(() => {
        for (const d of [-1, 1]) {
            細(() => {
                // 外縷：自鬢起，繞耳外緣（±7.05）之外行，拂肩而歇
                M(d * 5.6, 9.4);
                C(d * 7.5, 10.2, d * 8.15, 11.6, d * 7.9, 13.4);
                C(d * 7.7, 14.9, d * 8.05, 16.2, d * 7.8, 17.6);
                C(d * 7.55, 19.0, d * 8.1, 20.4, d * 7.8, 21.7);
                Qk(d * 8.5, 23.3, d * 9.6, 24.4);
                S();
                bi.A(d * 9.75, 24.8, 0.38, Math.PI * 1.25, Math.PI * 0.55);
                // 內縷：於耳上入耳後（斷筆），出於垂埵之下再續
                M(d * 5.45, 9.7);
                C(d * 6.5, 10.6, d * 7.0, 11.4, d * 7.05, 12.2);
                S();
                M(d * 6.6, 19.3);
                Qk(d * 6.75, 20.3, d * 7.1, 21.1);
                Qk(d * 7.6, 22.4, d * 8.35, 23.5);
                S();
                bi.A(d * 8.5, 23.9, 0.32, Math.PI * 1.25, Math.PI * 0.55);
            });
        }
    });
}
